import React from 'react';

interface AssetToolbarProps {
  selectedCount: number;
  onAddNew: () => void;
  onDeleteSelected: () => void;
  onClearFilters: () => void;
  onSelectColumns: () => void;
}

const AssetToolbar: React.FC<AssetToolbarProps> = ({
  selectedCount,
  onAddNew,
  onDeleteSelected,
  onClearFilters,
  onSelectColumns,
}) => {
  return (
    <div className="rounded-3xl border border-slate-200 bg-white px-5 py-5 shadow-sm">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div className="text-sm text-slate-500">Assets Actions</div>
        <div className="flex flex-wrap items-center gap-3">
          <button
            type="button"
            onClick={onAddNew}
            className="rounded-2xl bg-blue-600 px-4 py-2 text-sm font-semibold text-white shadow-sm transition hover:bg-blue-700"
          >
            + Add new
          </button>
          <button
            type="button"
            onClick={onDeleteSelected}
            className="rounded-2xl border border-slate-300 bg-white px-4 py-2 text-sm font-semibold text-slate-700 transition hover:bg-slate-50"
          >
            Delete{selectedCount > 0 ? ` (${selectedCount})` : ' (selected)'}
          </button>
        </div>
      </div>

      <div className="mt-4 flex flex-col gap-3 sm:flex-row sm:justify-end">
        <button
          type="button"
          onClick={onClearFilters}
          className="rounded-2xl border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 transition hover:bg-slate-50"
        >
          Clear All Filters
        </button>
        <button
          type="button"
          onClick={onSelectColumns}
          className="rounded-2xl border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 transition hover:bg-slate-50"
        >
          Select Columns
        </button>
      </div>
    </div>
  );
};

export default AssetToolbar;
